INSERT INTO `categories` (`id`, `vendor_id`, `name`, `slug`, `image`, `mobile_image`, `description`, `sort`, `status`, `discount`, `created_at`, `updated_at`) VALUES
(2, 5, 'Burgers', 'burgers', 'category_698885d2ada52.png', 'category_mobile_698885d3bfccb.png', 'Spicy and flavorful Mexican dishes  Spicy and flavorful Mexican dishes \r\n Spicy and flavorful Mexican dishes', 3, 1, 1, NULL, '2026-02-08 12:47:16'),
(3, 5, 'Indian', 'indian', 'category_697e6a08efcb3.png', 'category_mobile_697e6a09a268b.png', 'Japanese sushi is a traditional dish featuring vinegared rice, often combined with raw fish, seafood, and vegetables. It is meticulously crafted and presented, emphasizing freshness and balance. Sushi offers diverse varieties, including nigiri, maki, and sashimi, each showcasing the harmony of flavors and textures unique to Japanese cuisine.', 5, 1, 1, NULL, '2026-01-31 20:46:01'),
(4, 5, 'Pasta', 'pasta', 'category_697e6cf305d0a.jpg', 'category_mobile_67d54f6263f98.png', 'American BBQ is a culinary tradition known for slow-cooking meat over wood or charcoal, infusing it with rich, smoky flavors. Popular styles include Texas brisket, Carolina pulled pork, and Kansas City ribs. BBQ emphasizes tender, flavorful meats, complemented by tangy sauces and regional sides like coleslaw and cornbread.', 6, 0, 0, NULL, '2026-01-31 21:02:09'),
(5, 5, 'Fries', 'fries', 'category_697e6ad938ff5.png', 'category_mobile_697e6ef1c8aae.jpg', 'French pastries are renowned for their delicate textures and rich flavors, crafted with precision and artistry. Classics like croissants, éclairs, and macarons showcase buttery layers, sweet fillings, and exquisite presentation. These pastries embody the elegance and tradition of French baking, offering a perfect balance of taste and visual appeal in every bite.', 7, 1, 1, NULL, '2026-01-31 21:06:57'),
(6, 5, 'Chicken', 'curry', 'category_697e7259d8890.png', 'category_mobile_697e727a76ed0.png', 'Indian curry is a flavorful dish that blends aromatic spices, herbs, and a variety of ingredients like vegetables, meats, or legumes. Each region in India offers unique curry variations, from creamy, coconut-based curries in the south to rich, tomato-based gravies in the north. It’s a vibrant, hearty dish central to Indian cuisine.', NULL, 1, 1, NULL, '2026-01-31 21:22:02'),
(7, 5, 'Chinese', 'chinese', 'category_66b4a8a19439c.jpg', 'category_mobile_67d54cddb06a5.png', 'Chinese dim sum is a traditional Cantonese cuisine featuring small, bite-sized dishes served in bamboo steamers or on small plates. It includes a variety of dumplings, buns, and pastries, often filled with meats, seafood, or vegetables. Dim sum is typically enjoyed with tea, making it a social dining experience rooted in Chinese culture.', NULL, 0, 0, NULL, '2026-01-31 21:09:10'),
(8, 5, 'Döner', 'doner', 'category_66b4a975eaeae.jpg', 'category_mobile_67d550b1bace4.png', 'Thai street food is a vibrant culinary experience offering a diverse array of flavorful dishes, often prepared fresh at bustling markets and roadside stalls. From spicy papaya salad and pad Thai to savory grilled meats and sweet mango sticky rice, Thai street food captures the bold, aromatic flavors of Thai cuisine, providing an authentic and affordable taste of Thailand.', 8, 0, 0, NULL, '2026-01-31 21:24:01'),
(9, 5, 'Schnitzel', 'schnitzel', 'category_67d925563eda0.png', 'category_mobile_697e6eb0bcbfb.png', 'Greek Mediterranean cuisine is celebrated for its fresh, wholesome ingredients and vibrant flavors. Featuring dishes like olive oil-dressed salads, grilled meats, seafood, and savory dips like tzatziki, it emphasizes simplicity and balance. The cuisine showcases the abundant produce, herbs, and olive oil of the region, offering a healthy, flavorful taste of the Mediterranean lifestyle.', 9, 1, 1, NULL, '2026-01-31 21:23:54'),
(10, 5, 'Snacks', 'american', 'category_697e6b9de5bda.jpg', 'category_mobile_697e6b9e05814.jpg', 'Spanish tapas are small, flavorful dishes enjoyed as appetizers or snacks, reflecting the diverse culinary traditions of Spain. Ranging from savory olives and cured meats to intricate seafood and cheese creations, tapas are meant for sharing and sampling. This culinary style embodies Spain\'s social dining culture and vibrant food scene.', 3, 1, 1, NULL, '2026-01-31 21:49:15'),
(11, 5, 'American Pizza', 'american-style-pizza', 'category_697e7211f2b75.jpg', 'category_mobile_697e72122305b.jpg', 'Hearty Vietnamese noodle soup', 9, 1, 1, NULL, '2026-01-31 21:20:18'),
(12, 5, 'Salat', 'salat', 'category_697e75ea47d62.png', 'category_mobile_697e75eb3af66.png', 'Rodizio-style grilled meats from Brazil', NULL, 1, 1, NULL, '2026-01-31 21:36:43'),
(13, 5, 'Korean BBQ', 'korean-bbq', 'https://via.placeholder.com/300', NULL, 'Grilled Korean meats and kimchi', NULL, 0, 0, NULL, '2026-01-31 20:55:08'),
(14, 5, 'Middle Eastern Mezze', 'middle-eastern-mezze', 'https://via.placeholder.com/300', NULL, 'Assorted Middle Eastern appetizers', NULL, 0, 0, NULL, '2026-01-31 20:55:10'),
(15, 5, 'African Cuisine', 'african-cuisine', 'https://via.placeholder.com/300', NULL, 'Traditional dishes from various regions of Africa', NULL, 0, 0, NULL, '2026-01-31 20:55:20'),
(16, 5, 'Vegetarisch', 'vegetarian', 'category_697e736d9bbde.png', 'category_mobile_697e736ec96d8.png', 'Plant-based dishes for vegetarians and vegans', NULL, 1, 1, NULL, '2026-01-31 21:33:24'),
(17, 5, 'Gluten-Free Options', 'gluten-free-options', 'https://via.placeholder.com/300', NULL, 'Gluten-free versions of popular dishes', NULL, 0, 0, NULL, '2026-01-31 20:55:29'),
(18, 5, 'Seafood Specialties', 'seafood-specialties', 'category_697e68d1c8f85.jpg', 'category_mobile_697e68d1e650d.jpg', 'Fresh and flavorful seafood dishes', NULL, 1, 1, NULL, '2026-01-31 20:40:49'),
(19, 5, 'Dessert Delights', 'dessert-delights', 'category_697e6c67cc35f.jpg', 'category_mobile_697e6c67dfd0e.jpg', 'Decadent desserts and sweet treats', NULL, 1, 1, NULL, '2026-01-31 20:56:07'),
(20, 5, 'Vegan', 'street-food-favorites', 'category_697e74608504e.jpg', 'category_mobile_697e74609a41f.jpg', 'Popular street food dishes from around the world', NULL, 1, 1, NULL, '2026-01-31 21:31:19'),
(21, 5, 'Pasta', 'italian', 'category_697e6e0fdb38b.jpg', 'category_mobile_697e72c4c5698.jpg', 'A style of cooking where marinated meats and vegetables are skewered and cooked in a traditional clay oven (tandoor), resulting in a smoky, charred flavor.', 2, 1, 1, '2024-08-07 01:10:28', '2026-01-31 21:48:06'),
(23, 5, 'Pizza', 'pizza-indian', 'category_697e6968c493d.jpg', 'category_mobile_697e699c16f99.jpg', 'Indian pizza combines Italian pizza with Indian flavors, featuring paneer, tandoori chicken, spiced sauces like tikka masala, and Indian spices on a classic pizza base.', 1, 1, 1, '2024-09-07 07:59:50', '2026-01-31 21:47:04'),
(31, 9, 'Salat', 'salat-salate', 'category_67435be76aaf6.png', 'category_mobile_67435be7d79dd.png', 'Salat nach Wahl Klein, Groß dazu 1 x Dressing nach Wahl. Auf Wunsch extra Zutaten, Pizzabrot, Eis, alkoholfreie Getränke, alkoholische Getränke, Säfte, Softgtränke Kiste, Bier Kiste.', 2, 1, 1, '2024-10-08 08:42:01', '2025-03-21 09:08:37'),
(32, 9, 'Pizza Classic', 'pizza-classic', 'category_67435dbbc0c17.png', 'category_mobile_67435dbc5b04f.png', 'Alle Pizzen mit Tomatensauce und Käse (auf Wunsch auch ohne Käse). Auf Wunsch American Style, Extra Mozzarella im Pizzarand. Wahl aus: Klein Ø 26cm, Groß Ø 30cm, Family ca. 45x32cm, Party 60x40cm.', 4, 1, 1, '2024-10-08 10:05:34', '2025-03-21 09:08:37'),
(33, 9, 'Pizza Barbecue', 'pizza-barbecue', 'category_6743626e2a176.png', 'category_mobile_674362748ac37.png', 'Auf Wunsch American Style, Extra Mozzarella im Pizzarand. Wahl aus: Klein Ø 26cm, Groß Ø 30cm, Family ca. 45x32cm, Party 60x40cm. Alle Pizzen mit Barbecuesauce und Käse (auf Wunsch auch ohne Käse)', 5, 1, 1, '2024-10-08 11:08:58', '2025-03-21 09:08:37'),
(34, 9, 'Pizza Hollandaise', 'pizza-hollandaise', 'category_67436925a5f95.png', 'category_mobile_674369262af2d.png', 'Auf Wunsch American Style, Extra Mozzarella im Pizzarand. Wahl aus: Klein Ø 26cm, Groß Ø 30cm, Family ca. 45x32cm, Party 60x40cm. Alle Pizzen mit Hollandaisesauce und Käse (auf Wunsch auch ohne Käse).', 6, 1, 1, '2024-10-08 11:11:16', '2025-03-21 09:08:37'),
(36, 9, 'Pizza Hähnchen', 'pizza-hahnchen', 'category_67437fc0cc559.png', 'category_mobile_67437fc16afd1.png', 'Alle Pizzen mit Tomatensauce und Käse (auf Wunsch auch ohne Käse). Auf Wunsch American Style, Extra Mozzarella im Pizzarand. Wahl aus: Klein Ø 26cm, Groß Ø 30cm, Family ca. 45x32cm, Party 60x40cm.', 7, 1, 1, '2024-10-08 11:16:13', '2025-03-21 09:08:37'),
