(38, 9, 'Pizza Hot-Mix', 'pizza-hot-mix', 'category_67437f566606c.png', 'category_mobile_67437f56d260a.png', 'Alle Pizzen mit Tomatensauce und Käse (auf Wunsch auch ohne Käse). Auf Wunsch American Style, Extra Mozzarella im Pizzarand. Wahl aus: Klein Ø 26cm, Groß Ø 30cm, Family ca. 45x32cm, Party 60x40cm.', 9, 1, 1, '2024-10-08 11:21:45', '2025-03-21 09:08:37'),
(39, 9, 'Pizza Rindersalami & Sucuk', 'pizza-rindersalami-sucuk', 'category_67437cb706bc3.png', 'category_mobile_67437cb77c2ae.png', 'Alle Pizzen mit Tomatensauce und Käse (auf Wunsch auch ohne Käse). Auf Wunsch American Style, Extra Mozzarella im Pizzarand. Wahl aus: Klein Ø 26cm, Groß Ø 30cm, Family ca. 45x32cm, Party 60x40cm.', 10, 1, 1, '2024-10-08 11:23:47', '2024-11-24 19:21:27'),
