INSERT INTO `vendor_details` (`id`, `vendor_id`, `company_name`, `vendor_full_name`, `logo`, `banner`, `company_address`, `company_phone`, `company_email`, `restuarnat_title`, `categories`, `description`, `gst_number`, `pan_number`, `bank_account_number`, `bank_ifsc_code`, `bank_account_holder_name`, `isDelivery`, `isPickup`, `isTable`, `delivery_free`, `minimum_price`, `restaurant_status`, `isSponsored`, `created_at`, `updated_at`, `delivery_cost`, `min_prepare_time`, `max_prepare_time`, `vat`, `bank_name`, `company_country`, `company_state`, `company_city`, `company_zipcode`, `company_street`, `credit_card_commission`, `stripe_commission`, `paypal_commission`, `commission`, `commission_fixed`, `paypal_commission_fixed`, `stripe_commission_fixed`, `credit_card_commission_fixed`, `byemail`, `bywinorder`, `bysmartorder`, `fax`, `shop_url`, `latitude`, `longitude`) VALUES
(1, 9, 'Restaurant Pizzeria Dhillon', 'Dhillon Sulakhan', 'logo_67365fe19d901.jpeg', 'banner_6738980722eef.jpg', 'Khurja', '061552389', 'dhillons@hotmail.de', 'Pizza, Pasta, Burger, Salat', '[\"2\",\"21\",\"23\"]', 'Herzlich Willkommen im Restaurant Pizzeria Dhillon\r\n\r\nWo Leidenschaft in jedem Bissen auf Perfektion trifft. Unsere Reise begann 2008 mit einer einfachen, dennoch starken Liebe für Pizza, und sie ist das Herzstück unserer Speisekarte. Von klassischen Margheritas bis zu abenteuerlichen, gourmetartigen Kreationen werden unsere Pizzen mit den feinsten Zutaten zubereitet und knusprig perfekt gebacken.\r\n\r\nDoch das ist noch nicht alles, was wir anbieten. Unsere köstlichen Pizzabrote, frischen und knackigen Salate, Indischen Gerichte und verwöhnenden Burger erfüllen jeden Geschmack. Wir sind stolz darauf, vielfältige Geschmäcker zufriedenzustellen und sicherzustellen, dass für jeden etwas bei RESTAURANT PIZZERIA LIEFERSERVICE DHILLON dabei ist. Begleiten Sie uns auf einem kulinarischen Abenteuer, das so vielfältig wie köstlich ist!\r\n\r\nWir wünschen guten Appetit!', '0781162406', 'RFSG6366G', 'DE90508501500017009125', 'HELADEF1DAS', 'Sulakhan Dhillon', 1, 1, 1, 1, 10.99, 1, 1, '2024-08-05 08:35:47', '2026-02-11 16:24:32', 1.99, 15, 45, 'DE261609465', 'Sparkasse Darmstadt', 'Germany', 'Hessen', 'Griesheim/Darmstadt', '64347', 'Raiffeisenstraße 16', 3.00, 2.50, 2.00, 10, 0.00, 0.00, 0.00, 0.00, 1, 1, 0, '06155830428', 'https://www.pizza-dhillon.de', 49.8688006, 8.5492153),
(13, 37, 'Pizzeria Ragazzi', 'Sulakhan Dhillon', 'logo_6754125f53b90.jpg', 'banner_675411e28143a.png', 'Raiffeisenstraße 16, 64347 Griesheim Hessen', '06155824925', 'info@pizzaservice-ragazzi.de', 'Pizza, Pasta, Burger, indisch', '[\"23\",\"4\",\"9\"]', 'Pizzeria Ragazzi Original italienisches Restaurant Lieferservice', '00781 162 406', 'DE261609465', 'DE90508501500017009126', 'HELADEF1DAS', 'Sulakhan Dhillon', 1, 1, 1, 1, 10.00, 1, 0, '2024-12-07 09:14:11', '2025-07-15 05:41:35', 2.00, 15, 45, 'DE261609465', 'Sparkasse Darmstadt', 'Germany', 'Hessen', 'Griesheim', '64347', 'Raiffeisenstraße 16', 3.00, 2.50, 2.00, 10, 0.00, 0.00, 0.00, 0.00, 1, 1, 0, '06155830428', 'https://www.ragazzigriesheim.de', 49.8688006, 8.5492153),
